let interactive = {
  plane : document.createElement("canvas"),
  init(callback){
    // set key events
    document.addEventListener("keydown",(e)=>{
      this.char.walk(e);
      interactive.update();
    })
    this.char = new El("char",svg.src);
    document.body.append(this.plane);
    this.plane.style.position = "fixed";
    this.plane.style.left = "0";
    this.plane.style.top = "0";
    this.plane.style.width = "100px";
    this.plane.style.height = "100px";
    // load char sprite 
    // THIS MUST BE LAST BECOUSE OF CALLBACK()    
    this.char.img.onload = () => {    
      callback();
    } 
  },
  set(){
    this.ctx = this.plane.getContext("2d");
    this.ctx.width = window.innerWidth;
    this.ctx.height = window.innerHeight;
    this.update();
  },
  update(){
    this.ctx.clearRect(0, 0, this.ctx.width, this.ctx.height);

    this.ctx.drawImage(this.char.img, 
    this.char.cyle * 40, this.char.direction * 40, 40, 40, 
    //this.char.x, this.char.y, 100, 100);
    0, 0, this.plane.width, this.plane.height);
    
  }

}

class El {
  constructor(type = "static", src = "blank"){
    this.img = document.createElement("img");
    this.img.src = src;
    this.type = type;
    this.x = 0;
    this.y = 0;
    this.walking = false;
    if(this.type == "char"){
      this.cyle = 0;
      this.direction = 2;  
    }
  }

  walk(e){
    // console.log(this.walking);
    if(!this.walking){
      this.walking = true;
      let change = {};
      let distance = 300;
      let speed = 75;
      if(e.code == "ArrowDown"){
        // this.char.y += 10;
        this.direction = 1;
        change["top"] = distance;
      }
      if(e.code == "ArrowUp"){
        // this.char.y -= 10;
        this.direction = 0;
        change["top"] = -distance;
      }
      if(e.code == "ArrowRight"){
        // this.char.x += 10;
        this.direction = 2;
        change["left"] = distance;
      }
      if(e.code == "ArrowLeft"){
        // this.char.x -= 10;
        this.direction = 3;
        change["left"] = -distance;
      }     
      this.cyle = 2;
      
      let key = Object.keys(change);
      console.log("key : "+key)
      setTimeout(()=>{
        this.cyle = 1;

        let newValue = (interactive.plane.style[key].split("px")[0]*1 + (change[key]/3));
        console.log(newValue);
        interactive.update();
        interactive.plane.style[key] = newValue+"px";
        setTimeout(()=>{
          interactive.plane.style[key] = newValue+"px";
          // this[key] += change[key]/2;
          this.cyle = 2;
          setTimeout(()=>{
            interactive.plane.style[key] = newValue+"px";
            this.cyle = 0;
            this.walking = false;
            interactive.update();
          },speed)
          interactive.update();
        },speed)
        interactive.update();
      },speed)



    }
  }
}


// load all values :D
interactive.init(()=>{
  interactive.set();
    
})
// reset values after window resize
window.onresize = () => {
  interactive.set();
}
